#!/bin/bash\n\n# ============================================\n# N8N REVENUE SYSTEM TEST SCRIPT\n# ============================================\n# Tests all components and generates sample leads\n\necho \"🧪 N8N Revenue System - Comprehensive Test\"\necho \"==========================================\"\necho \"\"\n\n# Colors\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m' # No Color\n\n# Test counters\nPASSED=0\nFAILED=0\n\n# Test function\ntest_endpoint() {\n    local name=$1\n    local url=$2\n    local method=${3:-GET}\n    local data=$4\n    \n    echo -n \"Testing $name... \"\n    \n    if [ \"$method\" = \"GET\" ]; then\n        response=$(curl -s -o /dev/null -w \"%{http_code}\" $url)\n    else\n        response=$(curl -s -o /dev/null -w \"%{http_code}\" -X $method -H 'Content-Type: application/json' -d \"$data\" $url)\n    fi\n    \n    if [ \"$response\" = \"200\" ] || [ \"$response\" = \"201\" ] || [ \"$response\" = \"202\" ]; then\n        echo -e \"${GREEN}✅ PASSED${NC} (HTTP $response)\"\n        ((PASSED++))\n    else\n        echo -e \"${RED}❌ FAILED${NC} (HTTP $response)\"\n        ((FAILED++))\n    fi\n}\n\necho \"1️⃣  TESTING CORE SERVICES\"\necho \"-------------------------------------------\"\n\n# Test Docker\necho -n \"Checking Docker... \"\nif command -v docker &> /dev/null; then\n    echo -e \"${GREEN}✅ PASSED${NC}\"\n    ((PASSED++))\nelse\n    echo -e \"${RED}❌ FAILED${NC}\"\n    ((FAILED++))\nfi\n\n# Test Docker Compose\necho -n \"Checking Docker Compose... \"\nif command -v docker-compose &> /dev/null; then\n    echo -e \"${GREEN}✅ PASSED${NC}\"\n    ((PASSED++))\nelse\n    echo -e \"${RED}❌ FAILED${NC}\"\n    ((FAILED++))\nfi\n\n# Check if containers are running\necho \"\"\necho \"2️⃣  CHECKING RUNNING CONTAINERS\"\necho \"-------------------------------------------\"\n\necho -n \"N8N Container... \"\nif docker ps | grep -q \"n8n_revenue_engine\"; then\n    echo -e \"${GREEN}✅ RUNNING${NC}\"\n    ((PASSED++))\nelse\n    echo -e \"${RED}❌ NOT RUNNING${NC}\"\n    ((FAILED++))\nfi\n\necho -n \"PostgreSQL Container... \"\nif docker ps | grep -q \"n8n_revenue_db\"; then\n    echo -e \"${GREEN}✅ RUNNING${NC}\"\n    ((PASSED++))\nelse\n    echo -e \"${RED}❌ NOT RUNNING${NC}\"\n    ((FAILED++))\nfi\n\necho \"\"\necho \"3️⃣  TESTING SERVICE ENDPOINTS\"\necho \"-------------------------------------------\"\n\ntest_endpoint \"N8N Health\" \"http://localhost:5678/api/v1/health\" \"GET\"\ntest_endpoint \"N8N Root\" \"http://localhost:5678\" \"GET\"\ntest_endpoint \"Webhook Demo\" \"http://localhost:5678/webhook/demo\" \"POST\" '{\"test\":\"data\"}'\n\necho \"\"\necho \"4️⃣  TESTING DATABASE CONNECTION\"\necho \"-------------------------------------------\"\n\necho -n \"PostgreSQL Connection... \"\nif docker exec n8n_revenue_db pg_isready -U revenue_admin 2>/dev/null | grep -q \"accepting\"; then\n    echo -e \"${GREEN}✅ CONNECTED${NC}\"\n    ((PASSED++))\nelse\n    echo -e \"${RED}❌ FAILED${NC}\"\n    ((FAILED++))\nfi\n\necho -n \"Counting Leads... \"\nlead_count=$(docker exec n8n_revenue_db psql -U revenue_admin -d n8n_revenue -tc \"SELECT COUNT(*) FROM leads;\" 2>/dev/null | tr -d ' ')\nif [ \"$lead_count\" -gt 0 ]; then\n    echo -e \"${GREEN}✅ $lead_count LEADS FOUND${NC}\"\n    ((PASSED++))\nelse\n    echo -e \"${RED}❌ NO LEADS${NC}\"\n    ((FAILED++))\nfi\n\necho -n \"Counting Conversions... \"\nconversion_count=$(docker exec n8n_revenue_db psql -U revenue_admin -d n8n_revenue -tc \"SELECT COUNT(*) FROM conversions;\" 2>/dev/null | tr -d ' ')\nif [ \"$conversion_count\" -gt 0 ]; then\n    echo -e \"${GREEN}✅ $conversion_count CONVERSIONS FOUND${NC}\"\n    ((PASSED++))\nelse\n    echo -e \"${YELLOW}⚠️  NO CONVERSIONS${NC}\"\nfi\n\necho \"\"\necho \"5️⃣  CREATING TEST LEAD\"\necho \"-------------------------------------------\"\n\ntest_timestamp=$(date +%s)\necho -n \"Submitting test lead... \"\n\nresponse=$(curl -s -X POST http://localhost:5678/webhook/lead-capture \\\n  -H 'Content-Type: application/json' \\\n  -d \"{\n    \\\"name\\\": \\\"Test User $test_timestamp\\\",\n    \\\"email\\\": \\\"test$test_timestamp@example.com\\\",\n    \\\"phone\\\": \\\"555-1234\\\",\n    \\\"company\\\": \\\"Test Company\\\",\n    \\\"company_size\\\": 100,\n    \\\"industry\\\": \\\"Technology\\\",\n    \\\"budget\\\": 50000,\n    \\\"timeline\\\": \\\"ASAP\\\",\n    \\\"source\\\": \\\"test_script\\\"\n  }\")\n\nif echo \"$response\" | grep -q \"received\"; then\n    echo -e \"${GREEN}✅ SUBMITTED${NC}\"\n    ((PASSED++))\n    \n    # Verify in database\n    echo -n \"Verifying in database... \"\n    sleep 2\n    lead_check=$(docker exec n8n_revenue_db psql -U revenue_admin -d n8n_revenue -tc \"SELECT COUNT(*) FROM leads WHERE email = 'test$test_timestamp@example.com';\" 2>/dev/null | tr -d ' ')\n    \n    if [ \"$lead_check\" -gt 0 ]; then\n        echo -e \"${GREEN}✅ VERIFIED${NC}\"\n        ((PASSED++))\n    else\n        echo -e \"${RED}❌ NOT FOUND${NC}\"\n        ((FAILED++))\n    fi\nelse\n    echo -e \"${RED}❌ FAILED${NC}\"\n    ((FAILED++))\nfi\n\necho \"\"\necho \"6️⃣  DATABASE STATISTICS\"\necho \"-------------------------------------------\"\n\necho \"Lead Qualification Distribution:\"\ndocker exec n8n_revenue_db psql -U revenue_admin -d n8n_revenue << 'EOF' 2>/dev/null\nSELECT \n  qualification_level,\n  COUNT(*) as count\nFROM leads\nGROUP BY qualification_level\nORDER BY count DESC;\nEOF\n\necho \"\"\necho \"Revenue Summary:\"\ndocker exec n8n_revenue_db psql -U revenue_admin -d n8n_revenue << 'EOF' 2>/dev/null\nSELECT \n  COUNT(*) as total_conversions,\n  COALESCE(SUM(revenue), 0) as total_revenue,\n  COALESCE(AVG(revenue), 0) as avg_deal_size\nFROM conversions;\nEOF\n\necho \"\"\necho \"7️⃣  SERVICE HEALTH STATUS\"\necho \"-------------------------------------------\"\n\necho \"N8N Health:\"\ncurl -s http://localhost:5678/api/v1/health | python -m json.tool 2>/dev/null || echo \"Unable to parse response\"\n\necho \"\"\necho \"===========================================\"\necho \"📊 TEST SUMMARY\"\necho \"===========================================\"\necho \"\"\necho -e \"${GREEN}✅ PASSED: $PASSED${NC}\"\necho -e \"${RED}❌ FAILED: $FAILED${NC}\"\necho \"\"\n\nif [ $FAILED -eq 0 ]; then\n    echo -e \"${GREEN}🎉 ALL TESTS PASSED!${NC}\"\n    echo \"\"\n    echo \"System is ready to use:\"\n    echo \"  📱 N8N Editor: http://localhost:5678\"\n    echo \"  🗄️  PgAdmin: http://localhost:5050\"\n    echo \"  💾 PostgreSQL: localhost:5432\"\n    echo \"\"\n    echo \"Next steps:\"\n    echo \"  1. Go to http://localhost:5678\"\n    echo \"  2. Import workflows from workflows/ folder\"\n    echo \"  3. Configure your API integrations\"\n    echo \"  4. Start capturing leads!\"\n    exit 0\nelse\n    echo -e \"${RED}⚠️  SOME TESTS FAILED${NC}\"\n    echo \"\"\n    echo \"Troubleshooting:\"\n    echo \"  1. Check if Docker is running: docker ps\"\n    echo \"  2. Check logs: docker-compose logs\"\n    echo \"  3. Restart services: docker-compose restart\"\n    echo \"  4. Start from scratch: docker-compose down && docker-compose up -d\"\n    exit 1\nfi\n"
